// src/components/Education.jsx
import { education } from '../data/portfolio';

export default function Education() {
  return (
    <section id="education" style={s.section}>
      <div style={s.inner}>
        <div className="reveal">
          <p style={s.label}>Education / Formación</p>
          <h2 style={s.title}>My background</h2>
        </div>

        <div style={s.grid}>
          {education.map((edu, i) => (
            <div
              key={i}
              className={`reveal reveal-delay-${i + 1}`}
              style={s.card}
              onMouseEnter={e => { e.currentTarget.style.borderColor = 'rgba(232,58,58,0.25)'; e.currentTarget.style.transform = 'translateY(-4px)'; }}
              onMouseLeave={e => { e.currentTarget.style.borderColor = 'var(--border)'; e.currentTarget.style.transform = 'none'; }}
            >
              <div style={s.degree}>{edu.degree}</div>
              <div style={s.school}>{edu.school}</div>
              <div style={s.period}>{edu.period} · {edu.location}</div>
            </div>
          ))}

          {/* Extra card */}
          <div
            className="reveal reveal-delay-4"
            style={{ ...s.card, borderColor: 'rgba(232,58,58,0.18)' }}
            onMouseEnter={e => { e.currentTarget.style.borderColor = 'rgba(232,58,58,0.35)'; e.currentTarget.style.transform = 'translateY(-4px)'; }}
            onMouseLeave={e => { e.currentTarget.style.borderColor = 'rgba(232,58,58,0.18)'; e.currentTarget.style.transform = 'none'; }}
          >
            <p style={s.extraLabel}>Formación complementaria</p>
            <div style={s.degree}>Primeros Auxilios</div>
            <div style={s.school}>Operario Industrial</div>
            <div style={s.period}>Carnet B · Vehículo propio</div>
          </div>
        </div>
      </div>
    </section>
  );
}

const s = {
  section:    { background: 'var(--bg)', padding: '100px 5%' },
  inner:      { maxWidth: 1200, margin: '0 auto' },
  label:      { fontSize: 11, fontWeight: 600, letterSpacing: '0.2em', textTransform: 'uppercase', color: 'var(--accent)', marginBottom: 10 },
  title:      { fontFamily: 'var(--font-head)', fontSize: 'clamp(30px, 5vw, 50px)', fontWeight: 800, letterSpacing: '-2px', color: 'var(--text)', marginBottom: 52 },
  grid:       { display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(260px, 1fr))', gap: 20 },
  card:       {
    background: 'var(--card)', border: '1px solid var(--border)',
    borderRadius: 12, padding: '28px 26px',
    transition: 'border-color 0.2s, transform 0.2s',
  },
  degree:     { fontFamily: 'var(--font-head)', fontSize: 16, fontWeight: 700, color: 'var(--text)', marginBottom: 6 },
  school:     { fontSize: 14, color: 'var(--accent2)', marginBottom: 4 },
  period:     { fontSize: 12, color: 'var(--text3)' },
  extraLabel: { fontSize: 10, fontWeight: 600, letterSpacing: '0.12em', textTransform: 'uppercase', color: 'var(--accent)', marginBottom: 10 },
};
